import { Convert } from 'pvtsutils';
import { PrivateKeyPossessionStatementAttribute } from './private_key_possession_statement_attribute';

describe('PrivateKeyPossessionStatementAttribute', () => {
  it('should return correct JSON structure', () => {
    /**
     * Name: Private Key Possession Statement
     * Contains signer information (issuer and serialNumber) and certificate
     * Note: The hex provided is the full Attribute structure (with OID wrapper)
     */
    const hexAttribute = '';
    const attribute = new PrivateKeyPossessionStatementAttribute(Convert.FromHex(hexAttribute));

    const json = attribute.toJSON();

    expect(json).toMatchSnapshot();
  });
});
